"""
MKT Christ Commentary — Psalms chapters 71–74
Run: python3 scripts/zc-christ-psalms-71-74.py

Source data used:
- data/interlinear/psalms.json
- data/translation/draft/mediating/psalms.json (MKT text)
- data/commentary/mkt-christ/psalms.json (continuity)

Key Christological decisions in this range:
- Ps 71:7 "astonishing sign" — Isa 8:18 (cited Heb 2:13: "I and the children God has given me");
  the righteous sufferer-as-sign is a type of Christ as the ultimate sign/portent of divine action.
- Ps 71:11 "God has abandoned him" — the precise accusation hurled at Jesus on the cross
  (Matt 27:43: "He trusts in God; let God rescue him now if he wants him"), a direct passion parallel.
- Ps 71:20 "from the depths of the earth you will bring me up" — one of the OT's clearest
  resurrection-language passages; the pattern Acts 2:24 attributes to Christ ("death could not
  keep its hold on him").
- Ps 72 — the Messianic Royal Psalm: every verse describes the ideal Davidic king who is
  fulfilled in Christ. v17 ("all peoples find blessing through him") = Gal 3:8 (Abrahamic
  blessing fulfilled in Christ). v8 (dominion from sea to sea) = Matt 28:18 (all authority).
  v11 (all kings bow) = Phil 2:10-11 (every knee). vv12-14 (precious blood of the poor) =
  1 Pet 1:19 (precious blood of Christ). This is the OT's most complete messianic portrait.
- Ps 73:17 — the sanctuary as the turning point of theodicy: the divine perspective obtained
  in the holy place resolves the crisis of the wicked's prosperity. In Christ, the believer
  enters the true sanctuary (Heb 10:19-22) and gains the eternal perspective.
- Ps 73:23-24 "you hold me by my right hand... afterward you will receive me into glory" —
  one of the OT's most explicit afterlife and glorification statements; fulfilled in Christ's
  resurrection and the believer's share in it (John 14:2-3; Phil 3:20-21).
- Ps 74:12 "bringing salvation in the midst of the earth" — the pivot of faith in a lament;
  the incarnation is the fulfillment: God's salvation enacted geographically and historically.
- Ps 74:13-14 cosmic victory over sea monsters/Leviathan — Christ's victory over death and
  the powers (Col 2:15; Heb 2:14; Rev 12:9-10).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ for Psalms 71-74 — old-age lament with passion parallels (Ps 71), the
#   messianic royal psalm (Ps 72), Asaph's theodicy resolved in the sanctuary (Ps 73), and
#   community lament over temple destruction with cosmic-battle pivot (Ps 74).
# CHANGE? If commentary/mkt-christ/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/psalms.json'));
#   [print(ch, len(d[ch])) for ch in ['71','72','73','74']]"

PSALMS = {
  "71": {
    "1": '<p>A theme: "In you, O LORD, I take refuge; let me never be put to shame." The opening of Psalm 71 nearly quotes Psalm 31:1 verbatim — the same refuge-claim and same shame-negation. The psalmist appears to be an elderly David (vv. 9, 18) revisiting the lament tradition of his youth. Romans 10:11 (citing Isa 28:16): "anyone who trusts in him will never be put to shame" — the "never be put to shame" of the lament tradition becomes the covenant promise of the gospel, grounded in trust in Christ. The refuge that the psalmist takes in YHWH is the refuge available to all in Christ, who is described as the "sure and steadfast anchor for the soul" (Heb 6:19).</p>',
    "2": '<p>A theme: "In your righteousness deliver me and rescue me; incline your ear to me and save me." The grounding of rescue in divine <em>ṣĕdāqāh</em> (righteousness) — not human merit but divine covenant faithfulness — is the OT foundation for Paul\'s concept of the "righteousness of God" in Romans. Romans 3:21-22: "the righteousness of God has been made known... through faith in Jesus Christ to all who believe." The deliverance and rescue that the psalmist appeals to through divine righteousness is what Christ accomplishes by being "made our righteousness" (1 Cor 1:30). The ear that inclines toward the cry of the righteous is the ear of the Father who "heard" Christ "because of his reverence" (Heb 5:7).</p>',
    "3": '<p>A theme: "Be for me a sheltering rock, a place I can always come to; you have commanded my salvation, for you are my rock and my fortress." The rock-fortress that is "always available" — the permanent, commanded salvation — is the security that Christ provides for those in him. Matthew 16:18: "on this rock I will build my church, and the gates of death will not overcome it." 1 Corinthians 10:4 identifies the rock with Christ directly. The "commanded salvation" (<em>ṣiwwîtā lehôšîa\'nî</em>) — salvation that comes by divine decree, not human effort — is the salvation given in Christ that the believer receives rather than achieves.</p>',
    "4": '<p>A theme: "Rescue me, O my God, from the hand of the wicked, from the grip of the unjust and cruel." The threefold enemy — the wicked, the unjust, the cruel — is the social and political reality of the righteous sufferer. The passion narrative embodies all three: the wicked (those who plotted; Mark 14:1), the unjust (Pilate, who knew Jesus was innocent; Luke 23:22), and the cruel (the mockers and soldiers of the crucifixion; Matt 27:27-31). Hebrews 5:7 (Christ "offered up prayers... to him who was able to save him from death") is the NT echo of this rescue-plea from the hand of the unjust.</p>',
    "5": '<p>A theme: "For you, O Lord GOD, are my hope, my trust from my earliest years." Trust rooted in earliest life — the faith formed in youth and carried through old age — is the model of perseverance the NT commends. 2 Timothy 1:5 (Timothy\'s faith, "which lived first in your grandmother Lois and in your mother Eunice") and Hebrews 11 (the catalogue of those who trusted "from their earliest years" through to death) develop this pattern. Christ himself trusted the Father "from his earliest years" (Luke 2:49: "I had to be in my Father\'s house") through to the cross.</p>',
    "6": '<p>A shadow: "I have depended on you from before I was born; you drew me safely out of my mother\'s womb. My praise is forever of you." The prenatal divine protection and birth as acts of divine faithfulness — the pattern of Psalms 22:9-10 and Isaiah 49:1 (the Servant: "before I was born the LORD called me") — is the shadow behind which Christ\'s conception and birth stand. Luke 1:35 (the Holy Spirit overshadowing Mary; the holy one conceived) and the Emmanuel-child of Isaiah 7:14 are the specific nativity fulfillments. The praise that begins before birth and extends forever anticipates the eternal praise of the Lamb (Rev 5:12-13).</p>',
    "7": '<p>A shadow: "I have been like an astonishing sign (<em>môfēt</em>) to many, but you are my strong shelter." The psalmist as a "sign/portent" to observers — a person whose suffering and trust in God makes them a visible object of wonder — is the pattern that Hebrews 2:13 applies to Christ. Hebrews 2:13 cites Isaiah 8:18 ("here am I, and the children God has given me" — the Servant and his community as signs from YHWH), placing it in Christ\'s mouth. Christ is the ultimate <em>môfēt</em>: the one whose life, death, and resurrection made him "a sign that will be spoken against" (Luke 2:34) and the astonishing portent of divine power over death (Acts 2:22: "accredited by God to you by miracles, wonders and signs").</p>',
    "8": '<p>A theme: "My mouth is full of your praise and your glory all the day long." The mouth perpetually filled with praise — the posture of sustained doxology — is the disposition Christ cultivates in his disciples (John 15:11: "that your joy may be complete") and that the redeemed community practices (Heb 13:15: "continually offer to God a sacrifice of praise — the fruit of lips that openly profess his name"). The "all the day long" of continuous praise anticipates the unceasing worship of the new creation: "day and night they never stop saying: \'Holy, holy, holy is the Lord God Almighty\'" (Rev 4:8).</p>',
    "9": '<p>A theme: "Do not reject me when old age comes; do not abandon me when my strength gives out." The fear of divine abandonment in weakness and aging — the request that divine faithfulness extend through the final stages of life — is the prayer that Christ\'s promise answers: "I will never leave you nor forsake you" (Heb 13:5, citing Deut 31:6, 8). The "strength giving out" (<em>kōhî kalōt</em>) is the human physical diminishment that makes divine sustaining grace most necessary. 2 Corinthians 12:9: "my grace is sufficient for you, for my power is made perfect in weakness." The God who does not abandon in old age is the Christ who says "I am with you always, to the very end of the age" (Matt 28:20).</p>',
    "10": '<p>A theme: "For my enemies speak about me; those who watch for my life conspire together." The conspiracy of enemies who discuss and plot against the righteous sufferer — their words as weapons before their acts — is the pattern of Jesus\'s Passion. Mark 14:1 ("the chief priests and the teachers of the law were looking for a way to arrest Jesus secretly and kill him") and John 11:53 ("from that day on they plotted to take his life") are the literal fulfillments. The "watching for my life" (<em>šōmĕrê nafšî</em> — those who guard/watch for a life to take it) is the hostile surveillance that surrounded Jesus\'s final week.</p>',
    "11": '<p>A direct anticipation: "They say, \'God has abandoned him; run him down and take him, for there is no one to rescue him.\'" This verse is a striking direct anticipation of the mockery at the cross. Matthew 27:43: "He trusts in God. Let God rescue him now if he wants him, for he said, \'I am the Son of God.\'" (Matthew\'s wording echoes Ps 22:8 as well, but the theme of "God has abandoned him" and "no one to rescue" is Ps 71:11\'s exact content.) Luke 23:35 describes bystanders who "sneered" as Jesus hung on the cross. The taunters of Psalm 71:11 are the taunters of Golgotha; the righteous sufferer who is mocked as God-forsaken is Christ, whom God does not ultimately abandon (the resurrection vindicates the trust).</p>',
    "12": '<p>A theme: "O God, do not be far from me; O my God, come quickly to my aid." The double petition — nearness and urgency — is the cry of the one who senses the divine withdrawal that accompanies deep suffering. The same cry appears in Psalm 22:11, 19 and is the template for the Gethsemane prayer (Matt 26:36-46). Hebrews 4:16: "let us then approach God\'s throne of grace with confidence, so that we may receive mercy and find grace to help us in our time of need." Christ is both the one who prayed this cry (in his earthly agony) and the one who ensures it is answered (as the intercessor and high priest at God\'s right hand).</p>',
    "13": '<p>A theme: "Let those who attack my life be put to shame and consumed; let those who seek my harm be wrapped in reproach and dishonor." The imprecation against persecutors — the prayer for divine reversal of their plans — is covenant realism: the moral order requires that violence against the righteous be answered. The NT does not repudiate this realism but transforms its timing and agent: Romans 12:19 ("do not take revenge... \'It is mine to avenge; I will repay\'"); and the eschatological judgment of Revelation 19-20 where those who made war against Christ and his people receive "reproach and dishonor." The putting-to-shame of the persecutors is guaranteed by the resurrection, which already vindicates the suffering righteous.</p>',
    "14": '<p>A theme: "But I will hope continually and will praise you more and more." The resolve of unceasing hope — hope that increases rather than diminishes under pressure — is the posture that Romans 5:3-5 describes as the fruit of suffering: "suffering produces perseverance; perseverance, character; character, hope. And hope does not put us to shame." Hebrews 12:1-3 grounds this increasing hope in "fixing our eyes on Jesus, the pioneer and perfecter of faith, who for the joy set before him endured the cross." The psalmist\'s "more and more" praise is what Christ\'s perseverance through suffering models and his Spirit enables.</p>',
    "15": '<p>A theme: "My mouth will proclaim your righteousness and your saving acts all the day long, for I cannot count their number." The uncountable divine saving acts — the surplus of righteousness and deliverance that exceeds calculation — is the theme that Hebrews 11 catalogs across the OT and that Paul alludes to in Romans 8:28-30. But the single saving act that encompasses all others — "reconciling the world to himself" (2 Cor 5:19) — is Christ\'s death and resurrection. The "righteousness" proclaimed in v15 is the <em>ṣĕdāqôt</em> (righteousnesses/righteous acts) of YHWH, fulfilled and concentrated in the one act that Romans calls "the righteousness of God" (Rom 1:17; 3:21-22).</p>',
    "16": '<p>A theme: "I will come in the strength of the Lord GOD; I will declare your righteousness — yours and no one else\'s." The exclusivity claim — "yours and no one else\'s" (<em>ki-attah levaddeka</em>, for you alone) — is the monotheistic insistence that righteousness belongs to YHWH alone, not to human achievement. Romans 3:10-12 establishes that no human is righteous; Romans 3:21-26 then declares that YHWH\'s own righteousness is given through Christ. The "declaring your righteousness alone" of Ps 71:16 is fulfilled in the apostolic proclamation that Christ\'s righteousness, not human merit, is the basis of salvation (Phil 3:9: "not having a righteousness of my own... but that which is through faith in Christ").</p>',
    "17": '<p>A revelation of God: "O God, you have taught me from my youth, and to this day I am still declaring your wonderful deeds." The lifelong divine instruction — God as teacher from youth through old age — is the relationship that Christ embodies perfectly and mediates for others. John 13:13: "you call me \'Teacher\' and \'Lord,\' and rightly so, for that is what I am." Matthew 23:10: "you have one Teacher, the Messiah." The "wonderful deeds" (<em>nifle-otekha</em>) that the psalmist declares are ultimately the miracles and wonders of Christ (Acts 2:22), which the disciples proclaimed throughout their lives.</p>',
    "18": '<p>A theme: "And even now in old age, with gray hair, O God, do not forsake me until I have proclaimed your strength to this generation and your power to all who are to come." The missional urgency of old age — to declare God\'s strength to the next generation before dying — is the pattern of the apostolic testimony. 2 Peter 1:13-15: "I think it is right to refresh your memory as long as I live in the tent of this body, because I know that I will soon put it aside... I will make every effort to see that after my departure you will always be able to remember these things." The transmission of divine strength-stories to future generations is the catechetical task that the apostolic church inherited and that the written NT preserves.</p>',
    "19": '<p>A revelation of God: "Your righteousness, O God, reaches the high heavens; you who have done such great things, O God — who is like you?" The incomparability of YHWH — the "who is like you?" (<em>mî kāmôkā</em>) that is the OT\'s monotheistic challenge to all rivals — is applied in the NT to Christ. Revelation 1:8 (Christ: "I am the Alpha and the Omega, says the Lord God, who is, and who was, and who is to come, the Almighty") and Colossians 1:16-17 ("all things were created through him and for him... in him all things hold together") deploy the incomparability claims to include the Son. The righteousness that "reaches the high heavens" is the righteousness of Christ, which covers "all who believe" (Rom 3:22).</p>',
    "20": '<p>A direct anticipation: "You who have made me experience many bitter troubles will revive me again; from the depths of the earth you will bring me up once more." The resurrection pattern stated explicitly: YHWH who permitted bitter troubles will <em>revive</em> (<em>tĕhayy-ênî</em>, give life again) and bring up (<em>ta\'ălēnî</em>, raise) from the depths of the earth. Acts 2:24: "God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him." This verse is one of the clearest OT statements of the resurrection hope applied to an individual — and the NT reads the same pattern in Christ\'s death and resurrection. The "depths of the earth" (<em>tĕhōmôt hā\'āreṣ</em>) parallels Ephesians 4:9\'s reference to Christ\'s descent to "the lower, earthly regions."</p>',
    "21": '<p>A theme: "You will increase my honor and surround me with comfort." The restoration of honor after humiliation — the divine vindication that follows the suffering — is the pattern of the Christological journey: "for the joy set before him, he endured the cross, scorning its shame, and sat down at the right hand of the throne of God" (Heb 12:2). Philippians 2:8-9: "he humbled himself by becoming obedient to death — even death on a cross! Therefore God exalted him to the highest place." The increase of honor in Ps 71:21 is the exaltation that the resurrection and ascension enact for Christ — the Father\'s vindication of the humiliated Son.</p>',
    "22": '<p>A revelation of God: "I will praise you with the lyre for your faithfulness, O my God; I will sing to you with the harp, O Holy One of Israel." "The Holy One of Israel" (<em>qĕdôš yiśrā\'ēl</em>) is Isaiah\'s distinctive title for YHWH — used 25 times in Isaiah, emphasizing the transcendent holiness of the covenant God. Mark 1:24 and Luke 4:34 report a demon addressing Jesus as "the Holy One of God" (<em>ho hagios tou theou</em>) — recognizing in him the same divine holiness Isaiah attributed to YHWH. John 6:69: Peter confesses "we have come to believe and to know that you are the Holy One of God." The praise due the Holy One of Israel in Ps 71:22 is due to Christ.</p>',
    "23": '<p>A theme: "My lips will shout for joy when I sing praises to you; and my soul, which you have redeemed, will also rejoice." The redeemed soul\'s joy — the integration of lips and soul in praise — is the NT ideal of authentic worship. John 4:24 ("God is spirit, and his worshipers must worship in the Spirit and in truth"); Ephesians 5:19 ("sing and make music from your heart to the Lord"). "My soul, which you have redeemed" — <em>nafšî \'ăšer pādîtāh</em> — the personal claim of redemption that grounds joy. 1 Peter 1:18-19: "redeemed... with the precious blood of Christ." The soul redeemed by Christ\'s blood is the soul whose joy is anchored in the redemption already accomplished.</p>',
    "24": '<p>A theme: "And my tongue will speak of your righteous deeds all day long, for those who sought to harm me have been put to shame and humiliated." The closing verse gathers the psalm\'s two threads: continuous proclamation of divine righteousness and the final shame of persecutors. The NT\'s eschatological form: Philippians 2:10-11 ("at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord") is the universal proclamation of the righteousness of God in Christ, before which even those who "sought to harm" the righteous sufferer will ultimately bow. The shame of the psalmist\'s enemies becomes the shame of all who opposed Christ at the final judgment.</p>',
  },
  "72": {
    "1": '<p>A type: "A Psalm of Solomon. O God, give the king your justice, and your righteousness to the king\'s son." Psalm 72 is the royal/messianic psalm par excellence: a prayer for the ideal king who will rule with divine justice and righteousness. The dual title — "the king" and "the king\'s son" — identifies the Davidic dynasty\'s heir as the recipient of divine governance qualities. The NT immediately recognizes this as the pattern fulfilled in Christ: the "king\'s son" who receives divine justice and righteousness is the Son of God who "is our righteousness" (1 Cor 1:30) and whose kingdom "will never end" (Luke 1:33). Every verse of Psalm 72 describes the Christ.</p>',
    "2": '<p>A type: "May he judge your people with righteousness and your poor with justice." The first characteristic of the ideal king: justice for the poor as the premier test of righteous rule. The prophets measure every king by this standard (Jer 22:15-16: "did not your father do right and justice? He judged the cause of the poor and needy — then it was well with him"). Christ applied Isa 61:1-2 to himself in Luke 4:18-19: "he has sent me to proclaim good news to the poor, to proclaim freedom for the prisoners... the year of the Lord\'s favor." Matthew 25:31-46 makes the final judgment turn on service to "the least of these" — the poor and needy of Ps 72:2.</p>',
    "3": '<p>A type: "May the mountains bring peace to the people, and the hills, through righteousness." The cosmic fruitfulness of the ideal king\'s reign — even the mountains and hills participating in the shalom he establishes — is the prophetic vision of the messianic age. Isaiah 11:6-9 ("the wolf will live with the lamb... the earth will be full of the knowledge of the LORD") and Isaiah 55:12 ("the mountains and hills will burst into song before you, and all the trees of the field will clap their hands") develop the same vision. Colossians 1:20: "through him to reconcile to himself all things, whether things on earth or things in heaven, by making peace through his blood, shed on the cross." The peace that the mountains bring in Ps 72:3 is the peace of Christ\'s reconciling work.</p>',
    "4": '<p>A type: "May he defend the cause of the poor of the people, give deliverance to the children of the needy, and crush the oppressor." The tripartite justice mandate — defend the poor, deliver the needy\'s children, crush the oppressor — is the agenda Christ announces and enacts. Luke 4:18 ("he has sent me to proclaim freedom for the prisoners and recovery of sight for the blind, to set the oppressed free"); James 5:1-6 (the divine reversal coming on exploitative oppressors). The "crushing of the oppressor" in Ps 72:4 is the same crushing of the devil\'s works that 1 John 3:8 attributes to Christ: "the Son of God appeared... to destroy the devil\'s work."</p>',
    "5": '<p>A type: "May they fear you as long as the sun and moon endure, through all generations." The endurance of the ideal king\'s reign coextensive with the created order — sun and moon as time-markers for his eternal kingdom — is the NT\'s claim about Christ\'s reign. Luke 1:33: "he will reign over Jacob\'s descendants forever; his kingdom will never end." Revelation 11:15: "the kingdom of the world has become the kingdom of our Lord and of his Messiah, and he will reign for ever and ever." The "all generations" of Ps 72:5 becomes the "for ever and ever" of the heavenly doxology, addressed to the Lamb.</p>',
    "6": '<p>A type: "May he be like rain falling on newly mown grass, like showers that water the earth." The king as life-giving rain — the agricultural image of royal blessing as the gift of new growth after cutting — is the Advent image. Isaiah 45:8: "you heavens above, rain down my righteousness; let the clouds shower it down. Let the earth open wide, let salvation spring up." Hosea 6:3: "he will come to us like the winter rains, like the spring rains that water the earth." John 7:38-39 (Christ as the source of living water springing up within believers) develops this rain-of-blessing image: Christ himself is the rain that produces spiritual fruitfulness in those who receive him.</p>',
    "7": '<p>A type: "In his days may the righteous flourish, and peace abound, until the moon is no more." The messianic era of righteous flourishing and peace without end — until the very consummation of the created order ("until the moon is no more") — is what Christ\'s kingdom inaugurates and will consummate. Romans 5:1: "we have peace with God through our Lord Jesus Christ." Romans 8:21: "the creation itself will be liberated from its bondage to decay and brought into the freedom and glory of the children of God." The peace "until the moon is no more" is the peace of the new creation where there is "no need of the sun or moon to shine" (Rev 21:23) because Christ is the light.</p>',
    "8": '<p>A direct anticipation: "May he have dominion from sea to sea, from the River to the ends of the earth." The universal dominion of the ideal king — from one horizon to the other, from the Euphrates to all the earth\'s boundaries — is explicitly fulfilled in the Great Commission. Matthew 28:18-19: "all authority in heaven and on earth has been given to me. Therefore go and make disciples of all nations." The dominion that Psalm 72:8 requests for Solomon\'s heir is claimed by Christ as already given by the Father. Revelation 11:15 announces its universal realization: "the kingdom of the world has become the kingdom of our Lord and of his Messiah."</p>',
    "9": '<p>A type: "May desert peoples bow before him, and his enemies lick the dust." The submission of enemies — even those from the remotest wilderness regions — before the ideal king anticipates the eschatological submission of all powers. Philippians 2:10: "at the name of Jesus every knee should bow, in heaven and on earth and under the earth." The "licking the dust" (<em>tsarav yelakku-afar</em>, lit. "his enemies will lick dust") is the extreme submission posture of ancient Near Eastern treaty language — total vassalage before the great king. Christ is the great King before whom even his enemies will ultimately acknowledge his sovereignty.</p>',
    "10": '<p>A type: "May the kings of Tarshish and the coastlands bring tribute; may the kings of Sheba and Seba offer gifts." The pilgrimage of distant kings bringing tribute — from Tarshish (far west, possibly Spain/Britain) and Sheba/Seba (Arabia/Ethiopia, far east/south) — is the image that Matthew 2:1-12 invokes for the Magi: wise men from the east bringing gold, incense (frankincense), and myrrh to the newborn king. The gifts of the Magi are the first installment of the tribute that Psalm 72:10 envisions. Revelation 21:24-26 shows the consummation: "the kings of the earth will bring their splendor into" the new Jerusalem, offering tribute to the Lamb.</p>',
    "11": '<p>A direct anticipation: "Yes, may all kings bow down before him; may all nations serve him." The universal submission of kings and nations — the total sovereignty of the ideal king over all earthly rulers — is the NT\'s claim about the risen Christ. Philippians 2:10-11: "at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord." Revelation 5:13: "to him who sits on the throne and to the Lamb be praise and honor and glory and power, for ever and ever!" The "all kings" and "all nations" of Ps 72:11 is the "every knee" and "every tongue" of Philippians — the same universal submission, named as what belongs to Christ.</p>',
    "12": '<p>A type: "For he delivers the needy when they cry for help, the poor and those who have no one to help them." The causal grounding of the ideal king\'s universal submission: he deserves it because he delivers the helpless. The reason for universal worship is the character of the king — his justice and compassion. Luke 4:18 applies this agenda to Christ; Matthew 9:36 describes his compassion for crowds "harassed and helpless, like sheep without a shepherd." The king who rules from sea to sea is also the king who attends to individual cries for help — and this combination is precisely what distinguishes Christ from all earthly rulers.</p>',
    "13": '<p>A type: "He has compassion on the weak and the needy, and saves the lives of the poor." The compassion-driven kingship — <em>yaḥmōl</em> (he spares, has compassion) on the powerless — is the character that runs throughout Jesus\'s healing ministry (Matt 14:14: "when Jesus landed and saw a large crowd, he had compassion on them and healed their sick"; Mark 1:41: "Jesus was indignant/moved with compassion"). The saving of the lives of the poor is not merely economic justice but existential rescue from the powers that diminish human life. Christ saves lives in the fullest sense: body, soul, and spirit, now and eternally (John 10:10: "I have come that they may have life, and have it to the full").</p>',
    "14": '<p>A type: "He redeems their life from oppression and violence, and their blood is precious in his eyes." The ideal king as redeemer — <em>yig\'al</em> (the kinsman-redeemer who buys back what was lost) — and the preciousness of the oppressed person\'s blood is the passage that 1 Peter 1:18-19 fulfills. "You were redeemed... not with perishable things such as silver or gold... but with the precious blood of Christ, a lamb without blemish or defect." The "precious blood" (<em>yāqār dāmām</em>) of the poor in Ps 72:14 is the blood that God considers costly enough to be worth the ransom-price of Christ\'s death. The redeemer-king of Psalm 72 who values the blood of the oppressed is the Christ who shed his own blood as their redemption price.</p>',
    "15": '<p>A type: "Long may he live! May gold from Sheba be given to him! May prayer be made for him continually and blessings pronounced for him all day long." The three prayers for the ideal king — long life, gifts of gold, continual intercession — are fulfilled in Christ uniquely. He lives forever (Rev 1:18: "I am the Living One; I was dead, and now look, I am alive for ever and ever!"). Gold was brought at his birth (Matt 2:11). And "prayer made for him continually" inverts in the NT: Christ himself makes continual intercession for his people (Heb 7:25: "he always lives to intercede for them"). The blessed king is also the priestly intercessor.</p>',
    "16": '<p>A type: "May grain be abundant throughout the land; may it wave on the mountaintops; may its yield be like Lebanon, and may the people of the city blossom like grass of the earth." The agricultural superabundance of the messianic reign — grain on the mountaintops, yield like the forests of Lebanon — is the eschatological harvest. John 4:35: "open your eyes and look at the fields! They are ripe for harvest" — Christ sees the harvest already coming through his mission. John 12:24: "unless a kernel of wheat falls to the ground and dies, it remains only a single seed. But if it dies, it produces many seeds." The grain that waves in the messianic era grows from the seed of Christ\'s death and resurrection.</p>',
    "17": '<p>A direct anticipation: "May his name endure forever; may it continue as long as the sun endures! May all peoples find blessing through him, and all nations will call him blessed." This verse is the Messianic Psalm\'s most explicit Christological content: "all peoples find blessing through him" is the Abrahamic promise of Genesis 12:3 ("all peoples on earth will be blessed through you") applied to the Davidic king. Galatians 3:8: "Scripture foresaw that God would justify the Gentiles by faith, and announced the gospel in advance to Abraham: \'All nations will be blessed through you.\'" Galatians 3:14: "he redeemed us in order that the blessing given to Abraham might come to the Gentiles through Christ Jesus." The "blessing through him" of Ps 72:17 is the blessing through Christ that Galatians declares fulfilled.</p>',
    "18": '<p>A revelation of God: "Blessed be the LORD, the God of Israel, who alone does wondrous things." The closing doxology of Book II of the Psalter — YHWH alone does wonders (<em>pelē\'</em>, the extraordinary acts that only God performs) — is the claim that the NT applies to Christ\'s miracles. John 5:36: "the works that the Father has given me to finish — the very works I am doing — testify that the Father has sent me." John 14:10: "the Father, living in me, is doing his work." The wondrous things that only YHWH does are done through Christ, because the one who does them is the same God disclosed in the Son (John 10:30: "I and the Father are one").</p>',
    "19": '<p>A revelation of God: "Blessed be his glorious name forever; may the whole earth be filled with his glory! Amen and Amen." The double amen that closes Book II of the Psalter — and the prayer for global glory-filling — is the eschatological vision that Habakkuk 2:14 shares ("the earth will be filled with the knowledge of the glory of the LORD as the waters cover the sea"). This vision is what Christ\'s mission accomplishes: "God chose to make known among the Gentiles the glorious riches of this mystery, which is Christ in you, the hope of glory" (Col 1:27). The "whole earth filled with his glory" is the consummation when "the kingdom of the world has become the kingdom of our Lord and of his Messiah" (Rev 11:15).</p>',
    "20": '<p>A theme: "The prayers of David, the son of Jesse, are ended." This editorial note closes Book II of the Psalter — it does not mark the end of Davidic psalms (more appear later) but of the collection that dominated this book. The Davidic authorship that this note emphasizes is the key to the NT\'s reading of the Psalter: the "son of David" who writes these prayers is pointing beyond himself to the ultimate Son of David, Jesus Christ (Matt 1:1; 22:41-45). The "prayers of David" are fulfilled not merely in their historical context but in the one whom David foresaw would sit on his throne "forever" (Acts 2:30-31).</p>',
  },
  "73": {
    "1": '<p>A theme: "A Psalm of Asaph. Truly God is good to Israel, to those who are pure in heart." The thesis of the psalm — its hard-won conclusion stated at the outset — is the claim that Matthew 5:8 expresses as a beatitude: "blessed are the pure in heart, for they will see God." The "pure in heart" (<em>bārê lēvāv</em>) who receive divine goodness in Psalm 73:1 are the "pure in heart" who see God in Matthew 5:8. The "seeing God" of the beatitude is what Psalm 73 builds toward in v23-24 (divine presence and reception into glory). Christ is both the embodiment of the pure-in-heart condition and the one through whom the impure are made pure (Heb 9:14: "how much more will the blood of Christ... cleanse our consciences").</p>',
    "2": '<p>A theme: "But as for me, my feet nearly slipped; my steps almost gave way." The near-fall of the righteous person under the pressure of theodicy-crisis — the almost-failure of faith when the wicked appear to prosper — is the honest anthropology that the NT assumes. 1 Corinthians 10:12: "if you think you are standing firm, be careful that you don\'t fall!" Jude 24: "to him who is able to keep you from stumbling" — the divine ability to prevent the fall that the psalmist nearly experienced. Christ is the keeper of the feet: "he will not let your foot slip" (Ps 121:3), the one "able to keep you from stumbling and to present you before his glorious presence without fault" (Jude 24).</p>',
    "3": '<p>A theme: "For I was envious of the arrogant when I saw how the wicked prosper." The envy of the wicked\'s prosperity — the crisis of faith that begins when the righteous observe that doing wrong seems to pay better than doing right — is the starting point of wisdom psalms and a universal human experience. Luke 15:28-30 (the elder brother\'s resentment at the prodigal\'s reception) captures the same envy-of-apparent-benefit-of-sin. The resolution in both cases: a change of perspective that sees the larger frame — the father\'s joy in restoration (Luke 15:31-32) and the divine sanctuary perspective of Ps 73:17. Christ enables this perspective-change by making the believer a citizen of the kingdom whose values run counter to the world\'s prosperity-calculus.</p>',
    "4": '<p>A theme: "For they have no anguish in their death; their bodies are sleek and strong." The apparent ease of the wicked\'s death — no visible struggle, no crisis of conscience visible — is the observation that troubles the righteous. But Hebrews 9:27: "just as people are destined to die once, and after that to face judgment." The sleek ease of the wicked\'s death is not the end of their story; the sanctuary perspective (v17) reveals their "end" (<em>\'aḥărîtām</em>) is destruction (v17-19). Luke 16:19-23 (Lazarus and the rich man) gives the narrative form: the rich man at ease in life, in torment after death; the suffering poor man, comforted.</p>',
    "5": '<p>A theme: "They are not in trouble like other people; they are not plagued like the rest of mankind." The exemption of the wicked from ordinary human suffering — their apparent immunity from the common troubles that afflict the righteous — is the observation that drives the theodicy crisis. The NT inverts this: suffering is the normal path of the righteous in Christ (John 16:33: "in this world you will have trouble. But take heart! I have overcome the world"; Rom 8:17: "if we are heirs, then we are co-heirs with Christ, if indeed we share in his sufferings in order that we may also share in his glory"). The immunity of the wicked from suffering is temporary; the sharing of Christ\'s suffering by the righteous leads to sharing his glory.</p>',
    "6": '<p>A theme: "Therefore pride adorns them like a necklace; violence wraps them like a garment." The social display of the wicked\'s pride and violence — worn ostentatiously, like jewelry and clothing — is the lifestyle critique that the prophets make of unjust power (Amos 4:1; Isa 3:16-24). James 5:1-5 targets the same pattern in the NT context. Christ\'s reversal: "blessed are the meek, for they will inherit the earth" (Matt 5:5) — the one who "did not consider equality with God something to be used to his own advantage" (Phil 2:6) is the antithesis of pride worn as a necklace. The cross itself is the ultimate reversal: the instrument of shame becomes the instrument of glory (1 Cor 1:18).</p>',
    "7": '<p>A theme: "Their eyes bulge with prosperity; the desires of their heart exceed all bounds." The excess of the wicked — prosperity that produces both physical abundance (bulging eyes of satiation) and unconstrained desire — is the spiral of covetousness that neither law nor social shame can contain. Luke 12:15: "be on your guard against all kinds of greed; life does not consist in an abundance of possessions." Colossians 3:5: "put to death... greed, which is idolatry." The unconstrained desire of v7 is the idolatry that Paul identifies — and its only remedy is the reorientation toward Christ who "is all, and is in all" (Col 3:11).</p>',
    "8": '<p>A theme: "They scoff and speak with malice; they talk of oppression with arrogance." The verbal malice of the wicked — their scoffing speech and arrogant talk of domination — is the pattern of those who stood around the cross: "those who passed by hurled insults at him, shaking their heads and saying, \'You who are going to destroy the temple and build it in three days, save yourself!\'" (Matt 27:39-40). The scoffing speech of Ps 73:8 reaches its darkest expression at Golgotha. But 1 Peter 2:23: "when they hurled their insults at him, he did not retaliate; when he suffered, he made no threats. Instead, he entrusted himself to him who judges justly."</p>',
    "9": '<p>A revelation of God: "They direct their mouths against the heavens, and their tongue ranges across the earth." The total presumption of the wicked — mouth against heaven, tongue sweeping the earth — is the pattern of the anti-divine power that Revelation calls "the beast." Revelation 13:5-6: "the beast was given a mouth to utter proud words and blasphemies... it opened its mouth to blaspheme God, and to slander his name and his dwelling place." The tongue-against-heaven of Psalm 73:9 is the blasphemy-against-God of Revelation 13 — and both are answered by the divine judgment that reveals their limits (Rev 17:14: "the Lamb will triumph over them because he is Lord of lords and King of kings").</p>',
    "10": '<p>A theme: "Therefore people keep returning to them, and a full cup of water is drained by them." The social magnetism of the wicked\'s success — people drawn to power and prosperity regardless of how it was obtained — is the human tendency that the prophets lament and that Christ addresses. John 5:44: "how can you believe since you accept glory from one another but do not seek the glory that comes from the only God?" The "returning to them" of v10 is the approval-of-human-praise that keeps people from authentic faith. Christ redirects this: "seek first his kingdom and his righteousness, and all these things will be given to you as well" (Matt 6:33).</p>',
    "11": '<p>A theme: "They say, \'How can God know? Does the Most High have knowledge?\'" The practical atheism of the prosperous wicked — denying divine omniscience as the basis for moral accountability — is the error that God directly addresses in Psalm 50:21 ("you thought I was like you") and that Romans 2:4-5 addresses: "do you presume on the riches of his kindness... not knowing that God\'s kindness is meant to lead you to repentance?" Christ\'s teaching on divine omniscience ("your Father, who sees what is done in secret, will reward you" — Matt 6:4, 6, 18) is the direct answer to "how can God know?" God sees; the judgment of Psalm 73:17-19 confirms it.</p>',
    "12": '<p>A theme: "See — these are the wicked, always at ease, growing in wealth." The summarizing observation of the crisis — the wicked as a class characterized by ease and growing wealth — is the observation that faith must reckon with without being destabilized by it. Hebrews 11:35b-38 describes the righteous who were tortured, mocked, imprisoned, killed — while the wicked prospered around them — "of whom the world was not worthy." The "always at ease" of the wicked in Ps 73:12 is contrasted implicitly with the persecuted righteous; the NT explicitly makes this contrast the expected pattern of the kingdom-age until the return of Christ.</p>',
    "13": '<p>A theme: "Surely I have kept my heart clean for nothing, and washed my hands in innocence in vain." The near-despair of righteousness under pressure — the temptation to conclude that moral faithfulness has no benefit — is the crisis of faith that the NT prepares for. Galatians 6:9: "let us not become weary in doing good, for at the proper time we will reap a harvest if we do not give up." Hebrews 12:3: "consider him who endured such opposition from sinners, so that you will not grow weary and lose heart." The "in vain" of Psalm 73:13 is exactly what Paul says the resurrection prevents from being true: "your labor in the Lord is not in vain" (1 Cor 15:58) — because the resurrection changes the moral calculus.</p>',
    "14": '<p>A theme: "For all day long I have been afflicted, and punishment comes every morning." The unrelenting experience of suffering by the righteous — punishment (<em>tôkahat</em>, discipline/chastisement) arriving with each morning — is the hardest form of faith\'s test. Romans 8:18: "I consider that our present sufferings are not worth comparing with the glory that will be revealed in us." 2 Corinthians 4:17: "for our light and momentary troubles are achieving for us an eternal glory that far outweighs them all." The daily punishment of Psalm 73:14 is part of the "all day long we face death" of Romans 8:36 — the experience of the covenant community that the resurrection of Christ answers.</p>',
    "15": '<p>A theme: "If I had said, \'I will speak this way,\' I would have betrayed the generation of your children." The self-restraint of the psalmist — refusing to voice his theodicy crisis publicly lest it damage others\' faith — is the pastoral responsibility that the NT teaches. Romans 14:1-15:3 (bearing with the weak in faith, not causing them to stumble); 1 Corinthians 8:9-13 (limiting freedom for the sake of weaker brothers). The "generation of your children" that the psalmist does not want to betray is the covenant community whose faith he protects. The pastoral ethic of protecting the faith of the vulnerable is modeled in Christ himself, who "did not please himself" (Rom 15:3) but served others\' needs.</p>',
    "16": '<p>A theme: "When I tried to make sense of all this, it was a torment before my eyes." The anguish of theodicy attempted by human reasoning alone — the mental torment when the problem of the wicked\'s prosperity is engaged without divine illumination — is what 1 Corinthians 1:21 names: "in the wisdom of God the world through its wisdom did not know God." The problem of evil and the prosperity of the wicked cannot be solved from within the human frame of reference. Paul\'s answer: "it pleased God through the foolishness of preaching to save those who believe" — the cross as the resolution of theodicy that human reasoning cannot reach, because it reframes the entire problem.</p>',
    "17": '<p>A direct anticipation: "until I entered the sanctuary of God; then I grasped their end." The sanctuary as the turning point — the sacred space where divine perspective displaces the distorted human view — is what the NT presents as the permanent access Christ provides. Hebrews 10:19-22: "we have confidence to enter the Most Holy Place by the blood of Jesus... let us draw near to God with a sincere heart and with the full assurance that faith brings." The psalmist had to physically enter the temple; believers enter the true sanctuary through Christ, permanently. The "grasping their end" that the sanctuary perspective provides is the eschatological clarity: "the end" of the wicked is judgment (v18-19); the "end" of the righteous is glory (v24).</p>',
    "18": '<p>A revelation of God: "Surely you have placed them on slippery ground; you cast them down to desolation." The sanctuary\'s perspective discloses what seemed like solid prosperity as precarious ground — the wicked\'s ease is a divinely-maintained slippery surface designed for their fall. Luke 20:18 (Jesus: "everyone who falls on that stone will be broken to pieces; anyone on whom it falls will be crushed") — the stone that is Christ is what the wicked build on at their peril. The "slippery ground" of Psalm 73:18 is what the rejection of Christ produces: "if you do not believe that I am he, you will indeed die in your sins" (John 8:24).</p>',
    "19": '<p>A revelation of God: "How suddenly they are destroyed, completely swept away by terrors!" The sudden destruction of the wicked — after apparently invulnerable prosperity — is the eschatological reversal that Luke 17:26-30 describes: "it was the same in the days of Lot... but the day Lot left Sodom, fire and sulfur rained down from heaven and destroyed them all. It will be just like this on the day the Son of Man is revealed." 1 Thessalonians 5:3: "while people are saying, \'Peace and safety,\' destruction will come on them suddenly." The "how suddenly" of Psalm 73:19 is the same suddenness that marks the Parousia for those unprepared.</p>',
    "20": '<p>A revelation of God: "Like a dream that vanishes when one awakes, so when you arise, O Lord, you despise their fleeting form." The wicked as a dream from which God\'s arising dispels the illusion — the prosperity of the godless as an insubstantial phantasm that divine intervention dissolves — is the eschatological vision. 2 Peter 3:10: "the day of the Lord will come like a thief. The heavens will disappear with a roar; the elements will be destroyed by fire." The "arising of the LORD" that wakes the world from the dream of the wicked\'s permanence is the Parousia of Christ: "when Christ, who is your life, appears, then you also will appear with him in glory" (Col 3:4). What seemed substantial — the world\'s power and the wicked\'s prosperity — dissolves; what was hidden — Christ and his people — is revealed.</p>',
    "21": '<p>A theme: "When my heart was embittered and I was pierced in my inner being." The somatic experience of theodicy-crisis — bitterness in the heart and piercing in the depths — is the full-person engagement with the problem of evil. Paul uses similar language for his anguish over Israel\'s unbelief: Romans 9:2 ("I have great sorrow and unceasing anguish in my heart"). The antidote is the same: the divine perspective that transforms the question. Philippians 4:7: "the peace of God, which transcends all understanding, will guard your hearts and your minds in Christ Jesus" — the piercing in the inner being guarded by the peace of Christ.</p>',
    "22": '<p>A theme: "I was brutish and ignorant; I was no better than an animal before you." The confession of bestial ignorance — the psalm\'s most radical self-abasement before divine wisdom — is the spiritual realism that precedes transformation. 1 Corinthians 2:14: "the person without the Spirit does not accept the things that come from the Spirit of God but considers them foolishness, and cannot understand them because they are discerned only through the Spirit." The "animal" state of theological ignorance is the pre-illumined condition; Christ\'s Spirit provides the illumination that elevates the believer from bestial incomprehension to divine wisdom (1 Cor 2:12-16).</p>',
    "23": '<p>A direct anticipation: "Yet I am always with you; you hold me by my right hand." The divine grip on the right hand — YHWH\'s inseparable hold on the covenant person — is the NT\'s "nothing will separate us" in its OT form. Romans 8:38-39: "neither death nor life, neither angels nor demons, neither the present nor the future, nor any powers, neither height nor depth, nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord." John 10:28-29: "I give them eternal life, and they shall never perish; no one will snatch them out of my hand... no one can snatch them out of my Father\'s hand." The right-hand holding of Ps 73:23 is the eternal grip of the Father through Christ.</p>',
    "24": '<p>A direct anticipation: "You guide me with your counsel, and afterward you will receive me into glory (<em>kāvôd</em>)." One of the OT\'s most explicit statements of personal afterlife and glorification: YHWH\'s guidance through life climaxes in being "taken into glory" (<em>qāḥanî</em> — the same taking verb used of Enoch, Gen 5:24, and Elijah, 2 Kgs 2). This is a clear anticipation of the NT\'s doctrine of glorification. Romans 8:30: "those he justified, he also glorified." John 14:2-3: "I am going there to prepare a place for you... I will come back and take you to be with me." Philippians 3:20-21: "our citizenship is in heaven... he will transform our lowly bodies so that they will be like his glorious body." The "received into glory" of Ps 73:24 is what Christ\'s resurrection makes possible for all who are in him.</p>',
    "25": '<p>A revelation of God: "Whom in heaven do I have but you? And on earth there is nothing I desire besides you." The exclusive orientation of the reoriented heart — after the sanctuary perspective resolves the theodicy crisis — is the <em>shema\'</em>-shaped devotion ("love the LORD your God with all your heart," Deut 6:5) in its most personal form. Matthew 22:37 (Christ citing the <em>shema\'</em>): "love the Lord your God with all your heart and with all your soul and with all your mind." Philippians 3:8 (Paul): "I consider everything a loss because of the surpassing worth of knowing Christ Jesus my Lord." The "nothing I desire besides you" of Psalm 73:25 is the heart that Paul describes when he says "for me to live is Christ" (Phil 1:21).</p>',
    "26": '<p>A revelation of God: "My flesh and my heart may fail, but God is the strength of my heart and my portion forever." The anticipated physical and emotional failure — and the simultaneous confidence in divine sufficiency beyond failure — is the eschatological faith of those who know their resurrection is secured. 2 Corinthians 4:16: "though outwardly we are wasting away, yet inwardly we are being renewed day by day." 2 Corinthians 12:9: "my grace is sufficient for you, for my power is made perfect in weakness." God as "my portion forever" (<em>ḥelqî lĕ\'ôlām</em>) — the inheritance that outlasts every bodily and emotional resource — is Christ himself: "Christ in you, the hope of glory" (Col 1:27).</p>',
    "27": '<p>A revelation of God: "For behold, those who are far from you will perish; you destroy all who are unfaithful to you." The judicial consequence of distance from YHWH — perishing as the end of the godless — is the negative background that makes the gospel\'s invitation urgent. Ephesians 2:12-13: "at that time you were separate from Christ, excluded from citizenship in Israel... without hope and without God in the world. But now in Christ Jesus you who once were far away have been brought near by the blood of Christ." The "far from you" of Psalm 73:27 is the condition that Christ\'s death remedies: "once you were alienated from God... but now he has reconciled you" (Col 1:21-22).</p>',
    "28": '<p>A revelation of God: "But as for me, it is good to be near God; I have made the Lord GOD my refuge, that I may declare all your works." The psalm concludes where Psalm 1 begins — with the contrast between the godless and the one whose life is oriented toward YHWH. The "nearness to God as good" (<em>ṭôv lî qorvat Elohim</em>) is the distilled wisdom of the entire theodicy journey. James 4:8: "come near to God and he will come near to you." Hebrews 10:22: "let us draw near to God with a sincere heart." The "making YHWH one\'s refuge" in order to "declare all his works" is the missional posture of the reoriented believer — and the motive is not self-benefit but proclamation: the sanctuary perspective produces testimony. Christ is both the refuge and the works to be declared (John 14:6; 1 John 1:1-3).</p>',
  },
  "74": {
    "1": '<p>A theme: "A Maskil of Asaph. O God, why have you rejected us forever? Why does your anger smolder against the sheep of your pasture?" The community lament in the face of catastrophic destruction — the temple burning, the people apparently abandoned — creates the theological crisis that the psalm works through. The "rejected forever?" (<em>lāneṣaḥ</em>) question is the lament tradition\'s sharpest challenge to covenant faithfulness. Psalm 22:1 ("My God, my God, why have you forsaken me?") is the individual form; Psalm 74 is its communal parallel. Both are placed in Christ\'s mouth at the cross (Matt 27:46) and both receive the same answer: not ultimate abandonment but temporary hiddenness that gives way to vindication.</p>',
    "2": '<p>A theme: "Remember your congregation, which you acquired long ago, the tribe of your inheritance, which you redeemed — Mount Zion, where you have dwelt." The prayer invoking three covenant claims — acquisition, inheritance, redemption — as grounds for divine action is the appeal to the covenant\'s history against the present crisis. The NT applies all three terms to Christ\'s work: "God has chosen you as a firstfruits to be saved" (2 Thess 2:13, <em>haireomai</em> = acquisition); "an inheritance that can never perish" (1 Pet 1:4); "redeemed... with the precious blood of Christ" (1 Pet 1:18-19). The congregation whose redemption is invoked in Ps 74:2 is the church that Christ "bought with his own blood" (Acts 20:28).</p>',
    "3": '<p>A theme: "Make your way to the perpetual ruins; the enemy has wrought complete destruction in the sanctuary." The appeal for divine presence in the midst of destruction — "make your way to the ruins" — is the request for the God who descended to Sinai (Exod 19:18-20) and inhabited the tabernacle (Exod 40:34-35) to return in presence and power. The NT\'s fulfillment: God did come to the ruins — not the ruins of the earthly temple (which was indeed destroyed by Rome in 70 CE) but to the ruins of human existence in the incarnation. Emmanuel — "God with us" (Matt 1:23) — is the ultimate divine making-his-way-to-the-ruins.</p>',
    "4": '<p>A theme: "Your enemies have roared in the midst of your assembly; they have set up their own banners as signs." The enemy occupation of the sacred space — the roaring of God\'s opponents in the very place of worship, replacing covenant signs with conquering banners — is the desecration pattern. Daniel 9:27 and Matthew 24:15 (the "abomination of desolation") develop this image. The ultimate enemy-in-the-sanctuary is the eschatological antichrist (2 Thess 2:4: "he will exalt himself over everything that is called God or is worshiped, so that he sets himself up in God\'s temple, proclaiming himself to be God"). Christ\'s return defeats this final desecration (2 Thess 2:8).</p>',
    "5": '<p>A theme: "They were like men wielding axes to fell a dense forest." The axes destroying the temple woodwork — the violence against what was built for beauty and worship — is the image of powers opposed to divine purposes using human tools for destruction. The NT\'s answer to this destruction is Christ\'s promise: "I will build my church, and the gates of death will not overcome it" (Matt 16:18). The axes that fell the forest cannot fell what Christ builds, because he builds with living stones (1 Pet 2:5) on the foundation that cannot be destroyed (1 Cor 3:11).</p>',
    "6": '<p>A theme: "All its carved paneling they smashed apart with axes and hammers." The deliberate destruction of the detailed craftsmanship of the temple — the painstaking work that Bezalel and his craftsmen invested (Exod 31:1-11; 1 Kgs 6:14-36) — is the violence of those who destroy what worshipers built. The irreplaceable losses of the temple\'s destruction point forward to what cannot be destroyed: Hebrews 12:28: "we are receiving a kingdom that cannot be shaken." The carved paneling that axes can smash gives way to the heavenly sanctuary whose craftsmanship surpasses any earthly artistry (Heb 8:2: "the true tabernacle set up by the Lord, not by a mere human being").</p>',
    "7": '<p>A shadow: "They set your sanctuary on fire; they defiled the dwelling place of your name by pulling it down to the ground." The burning of the sanctuary — the destruction of the place where the divine name dwelt — is the pattern that Jesus himself invokes for his own body: John 2:19: "destroy this temple, and I will raise it again in three days." John 2:21: "the temple he had spoken of was his body." The burning of the earthly sanctuary in Ps 74:7 is the type fulfilled in the death of Christ, the true temple; the raising it "in three days" is the antitype\'s resolution. The defilement of the dwelling place is answered by the resurrection of the body that is the true dwelling place of God (Col 2:9).</p>',
    "8": '<p>A theme: "They said in their hearts, \'We will crush them all together\'; they burned down every meeting place of God throughout the land." The comprehensive program of destruction — crushing the people and burning every meeting place — is the systematic persecution of the covenant community. Acts 8:3 describes a similar comprehensive assault: "Saul began to destroy the church. Going from house to house, he dragged off both men and women and put them in prison." Revelation 12:13-17 describes the dragon\'s comprehensive war against the woman and her offspring — "those who keep God\'s commands and hold fast their testimony about Jesus." But Revelation 12:11: "they triumphed... by the blood of the Lamb." The crushing that the enemies intend fails.</p>',
    "9": '<p>A theme: "We see none of our signs; there is no longer a prophet; and none of us knows how long this will last." The experience of prophetic silence — the absence of divine signs and the cessation of prophetic word — is the "exile between the testaments" experience. The 400 years between Malachi and John the Baptist (Luke 3:1-3) are the literal fulfillment of this experience: no prophet, no signs, no word of how long. Into this silence came John the Baptist (Luke 1:13-17: "he will bring back many of the people of Israel to the Lord their God... to make ready a people prepared for the Lord") and then Christ himself, the Word who fills the silence (John 1:1, 14). The "how long?" of Ps 74:9 was answered at the incarnation.</p>',
    "10": '<p>A theme: "How long, O God, will the enemy mock you? Is the adversary to revile your name forever?" The "how long?" of covenant lament — the question that tests divine faithfulness by pressing the duration of apparent inaction — is addressed to God\'s own reputation: the enemy\'s mocking is a mocking of the divine name. Revelation 6:10 (the martyrs under the altar): "How long, Sovereign Lord, holy and true, until you judge the inhabitants of the earth and avenge our blood?" The question of Psalm 74:10 reaches its NT form in the martyrs\' cry, and receives the same answer: the seals will be opened, the judgment will come, the name will be vindicated — through Christ, the Lamb who opens the seals (Rev 6:1).</p>',
    "11": '<p>A theme: "Why do you hold back your hand, your right hand? Draw it out from under your garment and act!" The summons for divine power to be deployed — the right hand unsheathed from inaction — is the prayer for theophanic intervention. Isaiah 52:10: "the LORD will lay bare his holy arm in the sight of all the nations." This "laying bare of the arm" is what Isaiah 53:1 uses as the context for the Servant\'s redemptive work ("to whom has the arm of the LORD been revealed?"). The right hand drawn out in Ps 74:11 is drawn out in the Servant\'s suffering and resurrection — the power exerted not in military conquest but in the cross and empty tomb. Acts 2:33: Christ is "exalted to the right hand of God."</p>',
    "12": '<p>A revelation of God: "Yet God my King is from of old, bringing salvation in the midst of the earth." The pivot of faith — the "yet" that turns from crisis to confidence — is grounded in the eternal divine kingship and the historical pattern of salvation. "Bringing salvation in the midst of the earth" (<em>po\'ēl yĕšû\'ôt bĕqerev hā\'āreṣ</em>) is one of the OT\'s most geographically specific salvation claims: in the center, the middle, the heart of the earth. The incarnation is exactly this: God bringing salvation geographically and historically, born in Bethlehem (Mic 5:2), dying outside Jerusalem (Heb 13:12: "Jesus also suffered outside the city gate"), rising "in the midst of the earth." The eternal King acts in the middle of history and the middle of geography.</p>',
    "13": '<p>A type: "You split the sea apart by your power; you shattered the heads of the sea monsters on the waters." The Exodus sea-splitting and the shattering of the sea-monster heads — mythologized cosmic battle fused with historical exodus event — is the OT\'s image of divine victory over the chaos powers. Colossians 2:15: "having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross." Hebrews 2:14: "since the children have flesh and blood, he too shared in their humanity so that by his death he might break the power of him who holds the power of death." The Exodus sea-victory is the type of Christ\'s cross-victory over the powers.</p>',
    "14": '<p>A type: "You crushed the many heads of Leviathan; you gave his carcass as food for the creatures of the wilderness." The crushing of Leviathan — the primordial sea monster of chaos, ancient Near Eastern mythology\'s ultimate anti-divine power — by YHWH is fulfilled in Christ\'s defeat of the serpent/dragon. Genesis 3:15 (the serpent\'s head to be crushed by the woman\'s offspring); Revelation 12:9 ("the great dragon was hurled down — that ancient serpent called the devil, or Satan"); Revelation 20:10 ("the devil, who deceived them, was thrown into the lake of burning sulfur"). The Leviathan whose "many heads" YHWH crushes is the dragon whose heads Christ wounds mortally (Rev 12:3-10). The cross is the decisive crushing blow.</p>',
    "15": '<p>A revelation of God: "You split open springs and streams; you dried up the ever-flowing rivers." The divine sovereignty over water — the same power that split the sea (v13) also provides fresh springs and dries rivers when needed — is the comprehensive control over what was most vital and most dangerous. Christ as the source of living water (John 4:14: "whoever drinks the water I give them will never thirst"); Revelation 22:1-2 ("the river of the water of life, as clear as crystal, flowing from the throne of God and of the Lamb"). The spring-splitting of Ps 74:15 reaches its eschatological form in the "river of life" that Christ and the Father provide together in the new creation.</p>',
    "16": '<p>A revelation of God: "The day belongs to you; the night also is yours; you established the light and the sun." The divine ownership of time — day and night, light and sun as YHWH\'s creations and property — is the creator\'s claim that the NT extends to Christ. Colossians 1:16-17: "all things were created through him and for him... in him all things hold together." John 1:4: "in him was life, and that life was the light of all mankind." John 8:12: "I am the light of the world." The day and night that belong to YHWH in Ps 74:16 belong to the one through whom they were made — and who calls himself "the light of the world," the one who established the very light he now embodies.</p>',
    "17": '<p>A revelation of God: "You have fixed all the boundaries of the earth; you have made both summer and winter." The creator\'s fixing of boundaries — territorial and seasonal — is the sovereignty that Acts 17:26 applies to Christ\'s providential governance of history: "from one man he made all the nations, that they should inhabit the whole earth; and he marked out their appointed times in history and the boundaries of their lands." The boundaries fixed in Ps 74:17 are the boundaries administered by the Christ through whom "all things hold together" (Col 1:17). Even the seasons and the geographical limits of nations are within his sovereign governance.</p>',
    "18": '<p>A theme: "Remember this, O LORD: the enemy has mocked, and a foolish people has reviled your name." The prayer invoking divine memory of the enemy\'s mockery — appealing to YHWH\'s own honor as the basis for action — is the covenant logic of the lament. Isaiah 52:5 uses the same logic: "those who rule them mock, and continually all the day long my name is despised" — and YHWH responds by sending the Servant. The mocking of the divine name in Ps 74:18 is met by the divine action of sending the Servant (Isa 52:13-53:12), whose vindication refutes the mockery. Christ\'s resurrection is the divine refutation of the cross\'s seeming confirmation of the mockery ("he trusts in God; let God rescue him now" — Matt 27:43).</p>',
    "19": '<p>A theme: "Do not hand over your dove to the pack of enemies; do not forget the community of your poor forever." The "dove" (<em>tôr</em>) as the image of the vulnerable covenant community — fragile as a dove before predators — is the image of the church as exposed and dependent on divine protection. Matthew 10:16: "I am sending you out like sheep among wolves." Luke 12:32: "do not be afraid, little flock, for your Father has been pleased to give you the kingdom." The dove-community of Ps 74:19 is the "little flock" of Jesus\'s discourse — vulnerable, apparently powerless, but held within the divine care that cannot be overridden.</p>',
    "20": '<p>A theme: "Look to your covenant, for the dark corners of the land are filled with dens of violence." The appeal to covenant fidelity — "look to your covenant" (<em>habbēṭ labrît</em>) — as the ground for divine action is the prayer that the new covenant answers definitively. Hebrews 8:6-7: "the ministry Jesus has received is as superior to theirs as the covenant of which he is mediator is superior to the old one, since the new covenant is established on better promises." The "looking to the covenant" of Ps 74:20 is met by the new covenant whose better promises are sealed in Christ\'s blood (Luke 22:20: "this cup is the new covenant in my blood").</p>',
    "21": '<p>A theme: "Do not let the oppressed be turned away in shame; let the poor and needy praise your name." The prayer for the oppressed not to return in shame — the hope that the powerless will be vindicated rather than humiliated — is the reversal that Christ\'s entire ministry enacts. Luke 1:52-53 (the Magnificat): "he has brought down rulers from their thrones but has lifted up the humble. He has filled the hungry with good things but has sent the rich away empty." Matthew 5:3-5: "blessed are the poor in spirit... blessed are those who mourn... blessed are the meek." The shame-turned-to-praise of Ps 74:21 is the reversal Christ pronounces blessed and guarantees through his kingdom.</p>',
    "22": '<p>A theme: "Rise up, O God, and defend your cause; remember how fools mock you every single day." The petition for divine self-defense — YHWH rising to vindicate his own cause against daily mockery — is the lament genre\'s boldest petition. In the NT this "rising up" happens through the resurrection: Acts 2:24 ("God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him") is the divine "rising" against the powers that mocked ("he trusted in God; let God rescue him now"). The risen Christ is God\'s defense of his own cause — the vindication of the one who was mocked as God-forsaken.</p>',
    "23": '<p>A theme: "Do not forget the clamor of your enemies; the uproar of those who defy you rises without ceasing." The final petition — that the clamor of the enemies not be forgotten, that the continuous defiance be registered for judgment — is the prayer for eschatological accountability. Revelation 16:19: "God remembered Babylon the Great and gave her the cup filled with the wine of the fury of his wrath." The divine memory that the psalmist petitions in Ps 74:23 is the same divine memory that acts in Revelation\'s judgments. The "clamor of enemies" that "rises without ceasing" is heard and answered by the God who is the Lamb — the one who was himself subjected to the enemies\' clamor at the cross, and who will therefore judge it with perfect knowledge (Rev 6:10).</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-christ', 'psalms', existing)
    print('Psalms 71-74 mkt-christ written.')

if __name__ == '__main__':
    main()
